// // This module calculates the quotient and remainder of an 8-bit division operation. If the divisor is zero, the quotient is set to zero and the remainder is set to the dividend.
module SRT_Divider(  
    input [7:0] dividend,  
    input [7:0] divisor,  
    output reg [7:0] quotient,  
    output reg [7:0] remainder  
);  
    always @(*) begin  
        if (divisor == 8'b0) begin  
            quotient = 8'b0;  
            remainder = dividend;  
        end else begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end  
    end  
endmodule
